const buildSpeakingSampleQuestionId = (part: 'part1' | 'part3', topicId: string, questionIndex: number) =>
  `${part}-${topicId}-${questionIndex}`

const buildSpeakingSampleTopicId = (part: 'part1' | 'part3', topicId: string) => `${part}-topic-${topicId}`

const normalizeSpeakingTopicQuestion = (value: string) =>
  String(value || '')
    .replace(/^Part\s*[13]\s*-\s*/i, '')
    .trim()

const getSpeakingTopicQuestionList = (target: Pick<SpeakingVideoSampleTarget, 'prompt' | 'cues'>) =>
  [target.prompt, ...(target.cues || [])].map(normalizeSpeakingTopicQuestion).filter(Boolean)

const wrapCanvasTextLines = (context: CanvasRenderingContext2D, text: string, maxWidth: number) => {
  const words = String(text || '').trim().split(/\s+/).filter(Boolean)
  if (!words.length) return []
  const lines: string[] = []
  let line = words[0] || ''
  for (let index = 1; index < words.length; index += 1) {
    const candidate = `${line} ${words[index]}`
    if (context.measureText(candidate).width > maxWidth && line) {
      lines.push(line)
      line = words[index] || ''
    } else {
      line = candidate
    }
  }
  if (line) lines.push(line)
  return lines
}

const normalizeSpeakingSampleLookupId = (value: string) =>
  String(value || '')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')

const hasUploadedSpeakingSampleAsset = (
  assets: Record<string, SpeakingSampleVideoAsset>,
  sampleId: string
) => Boolean(assets[sampleId]?.videoUrl || assets[normalizeSpeakingSampleLookupId(sampleId)]?.videoUrl)

const topicHasSpeakingSampleInBank = (
  topic: SpeakingTopic,
  mode: SpeakingTestMode,
  assets: Record<string, SpeakingSampleVideoAsset>
): boolean => {
  if (mode === 'part2') {
    if (hasUploadedSpeakingSampleAsset(assets, topic.id)) return true
    return Boolean(
      resolveSpeakingPart2SampleVideo({ id: topic.id, title: topic.title, prompt: topic.prompt })
    )
  }
  if (mode === 'part1' || mode === 'part3') {
    if (hasUploadedSpeakingSampleAsset(assets, buildSpeakingSampleTopicId(mode, topic.id))) return true
    const questions = getSpeakingTopicQuestionList(topic)
    return questions.some((_, index) =>
      hasUploadedSpeakingSampleAsset(assets, buildSpeakingSampleQuestionId(mode, topic.id, index))
    )
  }
  if (mode === 'full') {
    if (hasUploadedSpeakingSampleAsset(assets, topic.id)) return true
    if (hasUploadedSpeakingSampleAsset(assets, buildSpeakingSampleTopicId('part1', topic.id))) return true
    if (hasUploadedSpeakingSampleAsset(assets, buildSpeakingSampleTopicId('part3', topic.id))) return true
    const plan = buildFullExamPlanFromPromptAndCues(topic.prompt, topic.cues || [])
    return (
      plan.part1Questions.some((_, index) =>
        hasUploadedSpeakingSampleAsset(assets, buildSpeakingSampleQuestionId('part1', topic.id, index))
      ) ||
      plan.part3Questions.some((_, index) =>
        hasUploadedSpeakingSampleAsset(assets, buildSpeakingSampleQuestionId('part3', topic.id, index))
      )
    )
  }
  return false
}

const formatAdminCountdownClock = (seconds: number) => {
  const safeSeconds = Math.max(0, Math.ceil(Number(seconds) || 0))
  const minutes = Math.floor(safeSeconds / 60)
  const wholeSeconds = safeSeconds % 60
  return `${String(minutes).padStart(2, '0')}:${String(wholeSeconds).padStart(2, '0')}`
}

