type AttemptStage = 'idle' | 'prep' | 'speaking' | 'assessing' | 'result'

type AssessmentReport = {
  provider: string
  nextAttemptFocusThai?: string
  part3AnswerCoaching?: Array<{
    question: string
    missing: string[]
    suggestionThai: string
  }>
  mockFullReport?: {
    section1: {
      title: string
      introThai: string
      analysisThai: string
      grammarMistakes: Array<{
        issue: string
        evidence: string
        suggestion: string
      }>
    }
    section2: {
      title: string
      introThai: string
      analysisThai: string
      fluencyReport: ComponentReport
    }
    section3: {
      title: string
      introThai: string
      analysisThai: string
      lexicalReport: ComponentReport
      grammarReport: ComponentReport
    }
  }
  vocabularyLevelUpSuggestions?: Array<{
    sourcePhrase: string
    replacement: string
    level: string
    thaiMeaning: string
    reasonThai: string
    sourceQuestion?: string
  }>
  punctuatedTranscript?: string
  questionBreakdown?: Array<{
    question: string
    rawTranscript: string
    punctuatedTranscript: string
    annotations?: Array<{
      label: string
      issueType: string
      highlightText: string
      commentThai: string
    }>
  }>
  totalScore?: number
  rawFourComponentAverage?: number
  componentReports?: {
    grammar?: ComponentReport
    lexical?: ComponentReport
    fluency?: ComponentReport
  }
  overallBand: number
  criteria: {
    fluency: number
    lexical: number
    grammar: number
  }
  strengths: string[]
  improvements: string[]
  modelNotes: string
}

type AssessmentResult = AssessmentReport & {
  primaryProvider?: string
  comparisons?: Record<string, AssessmentReport>
  comparisonErrors?: string[]
  apiUsage?: {
    provider: string
    totalCalls: number
    totalPromptTokens: number
    totalCompletionTokens: number
    totalTokens: number
    inputCostUsd: number
    outputCostUsd: number
    totalCostUsd: number
    pricingVersion?: {
      source: string
      verifiedAt: string
    }
    calls?: Array<{
      id: number
      provider: string
      operation: string
      model: string
      modelFamily: string
      promptTokenCount: number
      candidatesTokenCount: number
      totalTokenCount: number
      inputCostUsd: number
      outputCostUsd: number
      totalCostUsd: number
    }>
  }
}

type ComponentReport = {
  band: number
  explanationThai: string
  requiredTicks: Array<{
    requirement: string
    isMet: boolean
    evidence: string[]
  }>
  plusOnePlan: Array<{
    quote: string
    fix: string
    thaiMeaning?: string
  }>
  plusOneChecklist?: Array<{
    requirement?: string
    statusThai?: string
    quote: string
    fix: string
    originalText?: string
    improvedText?: string
  }>
}

type SpeechRecognitionInstance = {
  continuous: boolean
  interimResults: boolean
  lang: string
  maxAlternatives?: number
  onresult: ((event: SpeechRecognitionEventLike) => void) | null
  onerror: ((event: { error: string }) => void) | null
  onend: (() => void) | null
  start: () => void
  stop: () => void
}

type SpeechRecognitionEventLike = {
  resultIndex: number
  results: {
    isFinal: boolean
    0: { transcript: string }
    length: number
  }[]
}

type WindowWithSpeechRecognition = Window & {
  webkitSpeechRecognition?: new () => SpeechRecognitionInstance
  SpeechRecognition?: new () => SpeechRecognitionInstance
}

type RecommendationLevel = 'B1' | 'B2' | 'C1'

type RecommendationItem = {
  level: RecommendationLevel
  phrase: string
  tip: string
  source?: 'sample' | 'topic' | 'intent' | 'general'
}

type AnswerReviewModalState = {
  question: string
  contextLabel: string
  questionIndex: number
  fullExamPhase: FullExamPhase | null
  fullExamPart1Index: number
  fullExamPart3Index: number
}

type ScriptReviewModalState = {
  title: string
  noteThai: string
  items: ScriptReviewItem[]
}

