const READING_MONTH_COLLECTION_REGEX =
  /\b(?:ielts\s+academic\s+reading\s+)?(jan(?:uary)?|feb(?:ruary)?|mar(?:ch)?|apr(?:il)?|may|jun(?:e)?|jul(?:y)?|aug(?:ust)?|sep(?:t|tember)?|oct(?:ober)?|nov(?:ember)?|dec(?:ember)?)\s+(\d{4})\b/i

const getReadingCollectionSortValue = (title: string) => {
  const normalized = String(title || '').trim().toLowerCase()
  const match = normalized.match(READING_MONTH_COLLECTION_REGEX)
  if (!match) return Number.MAX_SAFE_INTEGER
  const month = READING_COLLECTION_MONTH_ORDER[match[1]] ?? 99
  return Number(match[2]) * 12 + month
}

const getReadingMonthCollectionLabel = (title: string) => {
  const match = String(title || '').trim().match(READING_MONTH_COLLECTION_REGEX)
  if (!match) return String(title || '').trim() || 'Reading Collection'
  const month = READING_COLLECTION_MONTH_LABELS[match[1].toLowerCase()] || match[1]
  return `${month} ${match[2]}`
}

const isMonthlyReadingCollection = (exam: Pick<ReadingExamRecord, 'title' | 'collectionTitle' | 'parsedPayload'>) =>
  READING_MONTH_COLLECTION_REGEX.test(getReadingExamCollectionTitle(exam))

const compareReadingCollectionTitles = (first: string, second: string) => {
  const firstSort = getReadingCollectionSortValue(first)
  const secondSort = getReadingCollectionSortValue(second)
  return firstSort - secondSort || first.localeCompare(second)
}

const getReadingPassageSortValue = (exam: Pick<ReadingExamRecord, 'title' | 'parsedPayload' | 'createdAt'>) => {
  const titleMatch = String(exam.title || '').match(/Passage\s+(\d+)/i)
  if (titleMatch) return Number(titleMatch[1])
  const passageNumber = exam.parsedPayload?.passages?.[0]?.number
  return Number.isFinite(passageNumber) ? Number(passageNumber) : 99
}

const sortReadingExamsForMonthlyBank = (exams: ReadingExamRecord[]) =>
  [...exams].sort((first, second) => {
    const passageOrder = getReadingPassageSortValue(first) - getReadingPassageSortValue(second)
    if (passageOrder !== 0) return passageOrder
    return first.title.localeCompare(second.title) || Date.parse(first.createdAt || '') - Date.parse(second.createdAt || '')
  })

const hasExplicitReadingCollection = (exam: Pick<ReadingExamRecord, 'collectionTitle' | 'parsedPayload'>) =>
  Boolean(String(exam.collectionTitle || exam.parsedPayload?.collectionTitle || '').trim())

const inferReadingCategoryFromSource = (value: string): ReadingBankCategory => {
  const text = String(value || '')
  const passageMatches = [...text.matchAll(/READING PASSAGE\s+(\d+)/gi)].map((match) => Number(match[1]))
  if (passageMatches.includes(3) && !passageMatches.includes(1) && !passageMatches.includes(2)) return 'advanced'
  return 'normal'
}

const deriveReadingTitleFromPassageText = (value: string, category: ReadingBankCategory) => {
  const text = String(value || '').replace(/\r/g, '').trim()
  if (!text) return READING_CATEGORY_LABELS[category]
  const firstBlock = text
    .replace(/^READING PASSAGE\s+\d+\s*/i, '')
    .trim()
  const title = String(firstBlock.split('\n').find((line) => line.trim()) || '').trim()
  if (!title) return READING_CATEGORY_LABELS[category]
  return title
}

const splitCombinedReadingImport = (value: string) => {
  const text = String(value || '').replace(/\r/g, '').trim()
  if (!text) {
    throw new Error('Please paste the combined reading source first.')
  }
  const answerKeyMatch = text.match(/^READING PASSAGE\s+\d+:\s*/m)
  const passageMatch = text.match(/^READING PASSAGE\s+\d+\b(?!:)/m)

  if (!answerKeyMatch || answerKeyMatch.index === undefined) {
    throw new Error('Could not find the answer-key block. Keep headings like "READING PASSAGE 1:" before the Question blocks.')
  }
  if (!passageMatch || passageMatch.index === undefined) {
    throw new Error('Could not find the passage block. Keep headings like "READING PASSAGE 1" before each passage.')
  }

  const answerKeyStartsFirst = answerKeyMatch.index < passageMatch.index
  const rawAnswerKey = answerKeyStartsFirst
    ? text.slice(answerKeyMatch.index, passageMatch.index).trim()
    : text.slice(answerKeyMatch.index).trim()
  const rawPassageText = answerKeyStartsFirst
    ? text.slice(passageMatch.index).trim()
    : text.slice(passageMatch.index, answerKeyMatch.index).trim()

  const category = inferReadingCategoryFromSource(rawPassageText)

  return {
    title: deriveReadingTitleFromPassageText(rawPassageText, category),
    category,
    rawPassageText,
    rawAnswerKey
  }
}

const attachReadingCollectionToBulkItems = (
  exams: ReadingBulkUploadInput[],
  collectionTitle: string,
  releaseAt: string
): ReadingBulkUploadInput[] => {
  const fallbackCollection = String(collectionTitle || DEFAULT_READING_COLLECTION_TITLE).trim()
  const normalizedReleaseAt = normalizeReadingReleaseAtInput(releaseAt)
  return exams.map((exam) => ({
    ...exam,
    collectionTitle: String(exam.collectionTitle || fallbackCollection).trim(),
    ...(normalizedReleaseAt || exam.releaseAt
      ? { releaseAt: normalizedReleaseAt || normalizeReadingReleaseAtInput(String(exam.releaseAt || '')) || exam.releaseAt }
      : {})
  }))
}

const normalizeTextForLooseMatch = (value: string) =>
  String(value || '')
    .toLowerCase()
    .replace(/["'“”‘’.,!?;:()[\]{}]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()

const buildReadingHintNeedles = (hintExcerpt?: string) => {
  const raw = String(hintExcerpt || '').trim()
  if (!raw) return []

  const quotedSegments = [...raw.matchAll(/["“”']([^"“”']{4,}?)["“”']/g)]
    .map((match) => String(match[1] || '').replace(/\s+/g, ' ').trim())
    .filter((segment) => segment.length >= 8)
  if (quotedSegments.length) return [...new Set(quotedSegments)]

  const normalized = raw
    .replace(/^["'“”]+|["'“”]+$/g, '')
    .replace(/\s+/g, ' ')
    .trim()
  if (!normalized) return []

  const segments = normalized
    .split(/(?:\.\.\.|…)+|(?:\s+\/\s+)|(?:\s*;\s*)|\n+/)
    .map((segment) => segment.replace(/^["'“”]+|["'“”]+$/g, '').trim())
    .filter((segment) => segment.length >= 8)

  return segments.length ? [...new Set(segments)] : [normalized]
}

