  const startReadingFullTest = (specId: string) => {
    const spec = READING_FULL_TEST_SPECS.find((item) => item.id === specId)
    if (!spec) return
    const exam = buildReadingFullTestExam(spec, bankReadingExams)
    if (!exam) {
      setReadingExamError('This full reading test is not ready yet.')
      return
    }
    startReadingExam(exam.id)
  }

  const returnToReadingBank = (exam: ReadingExamRecord) => {
    setReadingAttemptStage('bank')
    setReadingExamError('')
    if (isGeneralTrainingReadingExam(exam)) {
      const meta = resolveGeneralTrainingExamMeta(exam)
      if (meta.gtKind === 'full') {
        openGeneralTrainingFullTests()
      } else if (meta.gtSection) {
        openGeneralTrainingReadingSection(meta.gtSection as GeneralTrainingReadingSection)
      } else {
        openGeneralTrainingReadingHub()
      }
      return
    }
    if (isMonthlyReadingCollection(exam)) {
      openReadingMonthlyBank()
      return
    }
    if (isReadingJourneyExamId(exam.id)) {
      openReadingJourneyBank()
      return
    }
    if (isReadingFullTestExamId(exam.id)) {
      openReadingFullTestBank()
      return
    }
    openReadingCategoryBank(exam.category)
  }

  const openListeningVocabularyBuilderPack = (packId: string) => {
    stopListeningPlayback()
    resetListeningBuilderExamDrill()
    setListeningLabMode('builder')
    setSelectedListeningBuilderPackId(packId)
    const selectedPack = listeningVocabularyBuilderPacks.find((pack) => pack.id === packId) || null
    const selectedExamSet =
      LISTENING_BUILDER_EXAM_SETS.find((examSet) => examSet.id === packId) ??
      LISTENING_BUILDER_EXAM_SETS.find(
        (examSet) => examSet.bookNumber === selectedPack?.bookNumber && examSet.sectionNumber === selectedPack?.sectionNumber
      )
    if (selectedExamSet) {
      setSelectedListeningBuilderExamTestId(selectedExamSet.tests[0]?.id || '')
    } else {
      setSelectedListeningBuilderExamTestId('')
    }
    setListeningBuilderItemIndex(0)
    setActivePage('listening_builder_exam')
  }

  const resetListeningBuilderExamDrill = () => {
    setListeningBuilderItemIndex(0)
    setListeningBuilderExamAudioPlayed(false)
    stopListeningPlayback()
    window.getSelection()?.removeAllRanges()
  }

  const startReadingExam = (examId: string) => {
    const exam = practiceReadingExams.find((item) => item.id === examId) || null
    if (!exam) return
    const isMonthlyExam = isMonthlyReadingCollection(exam)
    const isFullTestExam = isReadingFullTestExamId(examId)
    const isJourneyExam = isReadingJourneyExamId(examId)
    const isGeneralTrainingExam = isGeneralTrainingReadingExam(exam)
    setReadingWorkspaceMode('bank')
    setReadingEntryView(
      isGeneralTrainingExam
        ? 'general-training'
        : isMonthlyExam
          ? 'monthly'
          : isFullTestExam
            ? 'full-test'
            : isJourneyExam
              ? 'journey'
              : 'levels'
    )
    if (isGeneralTrainingExam) {
      setReadingEntryCategory('general-training')
      setSelectedReadingCategory('general-training')
      const meta = resolveGeneralTrainingExamMeta(exam)
      if (meta.gtKind === 'full') {
        setGeneralTrainingReadingView('full-test')
        setGeneralTrainingSection(null)
      } else if (meta.gtSection) {
        setGeneralTrainingReadingView('section')
        setGeneralTrainingSection(meta.gtSection as GeneralTrainingReadingSection)
      } else {
        setGeneralTrainingReadingView('hub')
        setGeneralTrainingSection(null)
      }
    } else {
      setReadingEntryCategory(isMonthlyExam ? null : exam.category)
      setSelectedReadingCategory(exam.category)
    }
    setSelectedReadingCollection('all')
    setReadingPdoySessionActive(false)
    setSelectedReadingExamId(exam.id)
    // Restore in-progress answers/highlights if user has them saved locally
    let restoredAnswers: Record<number, string> = {}
    let restoredHighlights: Array<{ id: string; passageNumber: number; text: string }> = []
    if (authSession?.email) {
      try {
        const key = makeScopedStorageKey(`ielts-reading-progress:${exam.id}`, authSession.email)
        const raw = localStorage.getItem(key)
        if (raw) {
          const parsed = JSON.parse(raw) as {
            answers?: Record<number, string>
            highlights?: Array<{ id: string; passageNumber: number; text: string }>
          }
          if (parsed && typeof parsed === 'object') {
            if (parsed.answers && typeof parsed.answers === 'object') restoredAnswers = parsed.answers
            if (Array.isArray(parsed.highlights)) restoredHighlights = parsed.highlights
          }
        }
      } catch {
        // ignore parse errors
      }
    }
    setReadingAnswers(restoredAnswers)
    setReadingReportItems([])
    setReadingAttemptStage('briefing')
    setReadingHintQuestionNumber(null)
    setReadingExamError('')
    setReadingSelectionText('')
    setReadingUserHighlights(restoredHighlights)
    setReadingPencilStrokes({})
    setReadingSmartPencilMode(false)
    setReadingActivePassageNumber(exam.parsedPayload.passages[0]?.number || 1)
    setActivePage('reading')
  }

